import{d as a}from"./index-CjyuK5MW.js";class t{async create(e){return(await a.post("/hr/leave-requests",e)).data}async getById(e){return(await a.get(`/hr/leave-requests/${e}`)).data}async list(e={}){return(await a.get("/hr/leave-requests",{params:e})).data}async update(e,s){return(await a.put(`/hr/leave-requests/${e}`,s)).data}async approve(e){return(await a.post(`/hr/leave-requests/${e}/approve`)).data}async reject(e,s){return(await a.post(`/hr/leave-requests/${e}/reject`,{rejectionReason:s})).data}async cancel(e){return(await a.post(`/hr/leave-requests/${e}/cancel`)).data}}const p=new t;export{p as l};
